local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LxPatchMgr:LxBaseMgr
local LxPatchMgr = classX("LxPatchMgr", LxBaseMgr)

local PJXPatchMgr = PJXCenter.PatchMgr
local PJXGameMgr = PJXCenter.GameMgr

local _ESteps_None = 0
local _ESteps_Query = 1
local _ESteps_CollectPatch = 2
local _ESteps_Verify = 3
local _ESteps_Download = 4
local _ESteps_UnloadBundle = 5
local _ESteps_CollectRepair = 6

local _ESteps_DownloadComplete = 98
local _ESteps_WaitUnloadBundle = 99
local _ESteps_Done = 100

---@region 父类重构
function LxPatchMgr:Initialize()
    LxBaseMgr.Initialize(self)
end

function LxPatchMgr:Dispose()

    LxBaseMgr.Dispose(self)
end

function LxPatchMgr:OnUpdate()
    if not self._step then return end
    if self._step == _ESteps_Done then return end

    if self._isVerifyDirty then
        self._isVerifyDirty = false
        self:FireVerifyProgress()
    end
    if self._isProgressDirty then
        self._isProgressDirty = false
        self:FireProgress()
    end

    if self._isStepDirty then
        self._isStepDirty = false
        self:TryNextStep()
    end

    if self._isWaitUnloadBundle then
        self:OnWaitUnloadBundle()
    end
end
---@endregion 父类重构

---@region 工具函数
local SIZE_KB = 1024
local FormatByteToStr = function(loadByte)
    loadByte = loadByte / SIZE_KB
    if loadByte > SIZE_KB then
        loadByte = loadByte / SIZE_KB
        loadByte = string.format("%.2fM", loadByte)
    else
        loadByte = string.format("%.2fK", loadByte)
    end
    return loadByte
end

function LxPatchMgr:CalcProgress()
    local total = self._totalDownloadBytes
    local current = self._currentDownloadBytes
    local progress = 1
    if total > 0 then
        progress = current * 1.0 / total
    end
    self._progress = progress
end
--进度通知
function LxPatchMgr:FireProgress()
    self:CalcProgress()
    FireEvent(EventNames.UPDATE_PROGRESS, self._progress)
    local total = FormatByteToStr(self._totalDownloadBytes)
    local current = FormatByteToStr(self._currentDownloadBytes)
    FireEvent(EventNames.UPDATE_TIPS_BY_ID, 6, current, total, tostring(math.floor(self._progress * 100)))

    FireEvent(EventNames.UPDATE_PROGRESS_CHANGE, 1, self._progress, current .. "/" .. total)
    FireEvent(EventNames.UPDATE_PROGRESS_HOT_RES, self._currentDownloadBytes)
end

function LxPatchMgr:FireVerifyProgress()
    FireEvent(EventNames.UPDATE_TIPS_BY_ID, 9, self._currentVerifyCount, self._totalVerifyCount)
end
---@endregion 工具函数

---@region c# 回调函数
function LxPatchMgr:InitCallback()
    if self._isInitCallback then
        return
    end
    self._isInitCallback = true

    PJXPatchMgr.StepCallback = function(...)
        self:OnStepCallback(...)
    end
    PJXPatchMgr.DownloadProgressCallback = function(...)
        self:OnDownloadProgressCallback(...)
    end
    PJXPatchMgr.DownloadErrorCallback = function(...)
        self:OnDownloadErrorCallback(...)
    end
    PJXPatchMgr.StartDownloadFileCallback = function(...)
        self:OnStartDownloadFileCallback(...)
    end
    PJXPatchMgr.VerifyProgressCallback = function(...)
        self:OnVerifyProgressCallback(...)
    end
end

function LxPatchMgr:OnVerifyProgressCallback(totalVerifyCount,  currentVerifyCount)
    self._totalVerifyCount = totalVerifyCount
    self._currentVerifyCount = currentVerifyCount
    self._isVerifyDirty = true
end

function LxPatchMgr:OnStepCallback(step, result)
    if self._step ~= step then
        return
    end
    self._stepResult = result
    self._isStepDirty = true
end

function LxPatchMgr:OnDownloadProgressCallback(totalDownloadCount,  currentDownloadCount,  totalDownloadBytes,  currentDownloadBytes)
    self._totalDownloadCount = totalDownloadCount
    self._currentDownloadCount = currentDownloadCount
    self._totalDownloadBytes = tonumber(tostring(totalDownloadBytes))
    self._currentDownloadBytes = tonumber(tostring(currentDownloadBytes))

    self._isProgressDirty = true
end

function LxPatchMgr:OnDownloadErrorCallback(fileName, error)
    table.insert(self._errorFiles, {name=fileName, error = error})
    self._isErrorRecordDirty = true
end

function LxPatchMgr:OnStartDownloadFileCallback(fileName, sizeBytes)
    table.insert(self._startDownloadFiles, {name=fileName, size = tonumber(tostring(sizeBytes))})
    self._isStartDownloadDirty = true
end

---@engregion c# 回调函数

---@region 更新流程
function LxPatchMgr:SetRemoteUrl(mainUrl, fallbackUrl)
    self._mainUrl = mainUrl
    self._fallbackUrl = fallbackUrl
end

function LxPatchMgr:StartPatch(appVersion, packageVersion, isRepairMode)
    self._appVersion = appVersion
    self._packageVersion = packageVersion
    self._isRepairMode = isRepairMode

    self:PreparePatch()

    self._isStepDirty  = true
end

function LxPatchMgr:InitPatchDataInfo()
    local patchInfo = PJXPatchMgr.DataInfo
    if not patchInfo then
        patchInfo = PJX.PatchInfo.New()
        PJXPatchMgr.DataInfo = patchInfo
    end
    patchInfo.PatchPackageVersion = self._packageVersion
    patchInfo.PatchAppVersion = self._appVersion
    patchInfo.RemoteMainURL = self._mainUrl
    patchInfo.RemoteCallbackURL = self._fallbackUrl
    patchInfo.AppendTimeTicks = true
    patchInfo.Timeout = 60
    patchInfo.FailedTryAgain = 2
    patchInfo.DownloaderMaxNum = 8

    patchInfo.IsDone = false
    patchInfo.IsQueryRemoteSucceed = false
    patchInfo.IsCollectSucceed = false
    patchInfo.IsDownloadSucceed = false
    patchInfo.PatchVersionFile = nil
    patchInfo.PatchResManifest = nil
    patchInfo.PatchLuaManifest = nil
    patchInfo.ErrorFileNames:Clear()
    patchInfo.LoadedFileNames:Clear()
    patchInfo.BundleInfoList:Clear()
    patchInfo.IgnorePartIdList:Clear()

    self._patchInfo = patchInfo
end

function LxPatchMgr:ClearPatchInfo()
    local patchInfo = self._patchInfo
    if not patchInfo then return end

    patchInfo.ErrorFileNames:Clear()
    patchInfo.LoadedFileNames:Clear()
    patchInfo.BundleInfoList:Clear()
    patchInfo.IgnorePartIdList:Clear()
    patchInfo.VerifyElements:Clear()
    patchInfo.PackageBundles:Clear()
end


function LxPatchMgr:InitData()
    self._isProgressDirty = false
    self._isErrorRecordDirty = false
    self._isStartDownloadDirty = false
    self._isStepDirty = false
    self._totalDownloadCount = 0
    self._currentDownloadCount = 0
    self._totalDownloadBytes = 0
    self._currentDownloadBytes = 0
    self._progress = 0
    self._retryDownloadCnt = 0
    self._errorFiles = {}
    self._startDownloadFiles = {}
    self._isDownload = false
    self._step = _ESteps_None
    self._isWaitUnloadBundle = false
    self._waitUnloadBundleFrame = 0
    self._isSkipHotReload = false
end

function LxPatchMgr:PreparePatch()

    self:InitCallback()
    self:InitPatchDataInfo()
    self:InitData()

    if self._isRepairMode then
        --删除版本记录文件
        --修复文件，会删除坏掉的文件，先删除版本，成功后再记录
        PJXPatchMgr:RemoveVersionRecord()
    end
end

function LxPatchMgr:StartStep(step)
    self._step = step
    PJXPatchMgr:StartStep(step)
end

function LxPatchMgr:OnQueryError()
    FireEvent(EventNames.QUERY_REMOTE_FIlE_RESULT, false)
    gLxPatchCtrl:ShowSysTips(9, nil,function(btnType)
        if btnType == 2 then
            self:StartQueryRemoteFile()
        else
            QuitGame()
        end
    end)
end

function LxPatchMgr:OnCollectError()
    gLxPatchCtrl:ShowSysTips(101, nil,function(btnType)
        if btnType == 2 then
            self:StartCollectFile()
        else
            QuitGame()
        end
    end)
end

function LxPatchMgr:OnDownloadError()
    FireEvent(EventNames.UPDATE_FILE_ERROR, self._errorFiles)
    local errorInfo = self._errorFiles[#self._errorFiles]
    if errorInfo then
        FireEvent(EventNames.UPDATE_HOT_RES_FAILURE, errorInfo.name , self._totalDownloadBytes, errorInfo.error)
    end

    self._errorFiles = {}

    gLxPatchCtrl:ShowSysTips(102, nil,  function()
        self._retryDownloadCnt = self._retryDownloadCnt + 1
        self:StartCollectFile()
    end)
end

--从资源服务器下载资源文件
function LxPatchMgr:StartQueryRemoteFile()
    FireEvent(EventNames.UPDATE_TIPS_BY_ID, 3)
    self._step = _ESteps_Query
    self:StartStep(_ESteps_Query)

    FireEvent(EventNames.QUERY_REMOTE_FIlE_START)
end

--对比收集需要下载的文件，支持断点续传
function LxPatchMgr:StartCollectFile()
    FireEvent(EventNames.QUERY_REMOTE_FIlE_RESULT, true)

    FireEvent(EventNames.UPDATE_TIPS_BY_ID, 4)
    if self._isRepairMode then
        self._step = _ESteps_CollectRepair
        self:StartStep(_ESteps_CollectRepair)
    else
        self._step = _ESteps_CollectPatch
        self:StartStep(_ESteps_CollectPatch)
    end

end

function LxPatchMgr:StartVerifyFile()
    local needVerifyCount = self._patchInfo:GetNeedVerifyCount()
    if needVerifyCount == 0 then
        self:StartDownloadFile()
        return
    end
    self._totalVerifyCount = needVerifyCount
    self._currentVerifyCount = 0
    self:FireVerifyProgress()
    self._step = _ESteps_Verify
    self:StartStep(_ESteps_Verify)
end


--下载文件检查
function LxPatchMgr:StartDownloadFile()
    self._patchInfo:CreateDownloadList()
    local needDownloadCount = self._patchInfo:GetNeedTotalDownloadCount()
    if LOG_INFO_ENABLED then
        printInfo("patch", "需要下载的文件个数:%s", tostring(needDownloadCount))
    end
    if needDownloadCount == 0 then
        local diffCount = self._patchInfo.PackageBundles.Count
        if diffCount == 0 then
            --不需要热重载
            self._isSkipHotReload = true
        end
        self:StartDownloadComplete()
        return
    end

    local totalDownloadByte = tonumber(tostring(self._patchInfo:GetNeedTotalDownloadByte()))
    if LOG_INFO_ENABLED then
        printInfo("patch", "需要下载的文件大小:%s Kb", tostring(totalDownloadByte * 0.1 / 1024))
    end
    --移动网络 下载大于100M提示
    if not LPlatformUtil.IsWifiValid() then
        local limitSizeN = 100
        local limitAlertSize = 100 * 1048576 --100M , 1048576 = 1024 * 1024
        if totalDownloadByte > limitAlertSize then
            FireEvent(EventNames.UPDATE_NEED_HOT_RES, totalDownloadByte, false)

            local str = tostring(limitSizeN)

            gLxPatchCtrl:ShowSysTips(3, str, function(btnType)
                if btnType == 2 then
                    FireEvent(EventNames.UPDATE_BEGIN_HOT_RES, totalDownloadByte, false)
                    self:StartDownloadFileInternal()
                else
                    QuitGame()
                end
            end)
            return
        end
    end

    FireEvent(EventNames.UPDATE_NEED_HOT_RES, totalDownloadByte, true)
    FireEvent(EventNames.UPDATE_BEGIN_HOT_RES, totalDownloadByte, true)

    self:StartDownloadFileInternal()
end

--开始下载文件
function LxPatchMgr:StartDownloadFileInternal()
    FireEvent(EventNames.UPDATE_TIPS_BY_ID, 5)
    FireEvent(EventNames.UPDATE_START)
    self._step = _ESteps_Download
    self:StartStep(_ESteps_Download)
end

function LxPatchMgr:StartDownloadComplete()
    self._step = _ESteps_DownloadComplete

    if self._isRepairMode then
        FireEvent(EventNames.UPDATE_REPAIR_RES_OK)
    else
        FireEvent(EventNames.UPDATE_DOWNLOAD_RES_OK)
    end

    FireEvent(EventNames.UPDATE_PROGRESS, 1)
    FireEvent(EventNames.UPDATE_TIPS_BY_ID, 7)
    self._isStepDirty = true
end

function LxPatchMgr:RecordVersion()
    PJXPatchMgr:RecordPatchVersionFile(self._packageVersion)

    LxResUtil.SetRepairMode(false)
end

--等待几帧后重载
function LxPatchMgr:StartWaitUnloadBundle()
    if self._isSkipHotReload then
        --不需要热重载， 不卸载bundle直接结束
        self._step = _ESteps_Done
        ---资源版本更新为本次patch的版本
        PJXPatchMgr:ApplyToPatchVersion()
        if gLxPatchCtrl then
            gLxPatchCtrl:PrepareSetVersionInfo(true)
        end
        FireEvent(EventNames.UPDATE_FINISHED_WITHOUT_RELOAD)
        return
    end

    FireEvent(EventNames.UPDATE_TIPS_BY_ID, 8)
    self._step = _ESteps_WaitUnloadBundle
    self._waitUnloadBundleFrame = 15
    self._isWaitUnloadBundle = true
end

function LxPatchMgr:OnWaitUnloadBundle()
    if self._waitUnloadBundleFrame > 0 then
        self._waitUnloadBundleFrame = self._waitUnloadBundleFrame - 1
        return
    end
    self._isWaitUnloadBundle = false

    ---为热重载，清理持有的资源引用
    MgrCenter.ComponentMgr:ClearForHotReload()
    ---清理音频
    MgrCenter.SoundMgr:ClearAllSounds()
    ---清理持有的资源引用
    MgrCenter.ResourceMgr:ClearAllAssets()
    ---清理http
    MgrCenter.HttpMgr:ClearAllHttps()

    ---隐藏界面的 TextMesh控件， 删除ab的时候 text_mesh相关的shader和字体资源都会被卸载，
    ---不隐藏会导致资源找不到而抛渲染异常
    FireEvent(EventNames.UNLOAD_ALL_BUNDLE_PREPARE)

    self._step = _ESteps_UnloadBundle
    self:StartStep(_ESteps_UnloadBundle)
end

---卸载完ab包 重载lua
function LxPatchMgr:OnPatchFinished()
    self._step = _ESteps_Done

    ---资源版本更新为本次patch的版本
    PJXPatchMgr:ApplyToPatchVersion()

    if gLxPatchCtrl then
        gLxPatchCtrl:PrepareSetVersionInfo(true)
    end
    ---重载Lua， 由lua虚拟机宿主调用,
    ---有lua本身调用， 会因为在计时器中 使用，会造成不可预测异常，
    ---因此在Lua 环境的宿主中调用
    PJXGameMgr:SetLuaHotReload()
end

---由宿主语言调用的热重载lua函数
function LxPatchMgr:OnLuaHotReload()
    --清理给 c#设置的lua回调
    self:ClearCallback()

    --先删除所有计时器
    MgrCenter.TimerMgr:ClearAllTimers()
    LxTimer.ClearTimer()
    --不延迟一帧会造成宿主语言的堆栈异常
    --timer 会在结束的时候自动回收，此处特别写
    local timer = LxNFrameTimer.New(function()
        gLxLauncher:RestartByReload()
    end, nil, 1)
    timer:Start()
end

function LxPatchMgr:ClearCallback()
    self._isInitCallback = false
    PJXPatchMgr.StepCallback = nil
    PJXPatchMgr.DownloadProgressCallback = nil
    PJXPatchMgr.DownloadErrorCallback = nil
    PJXPatchMgr.StartDownloadFileCallback = nil
    PJXPatchMgr.VerifyProgressCallback = nil
end

--执行步骤
function LxPatchMgr:TryNextStep()
    --TODO 如果是从游戏内返回进行热更的，还需要考虑将正在下载的文件停止掉，减少下载流量（当前边从web加载边玩，并没有实现，所以当前未写这段逻辑）
    if self._step == _ESteps_None then
        self:StartQueryRemoteFile()
    elseif self._step == _ESteps_Query then
        if not self._stepResult then
            self:OnQueryError()
            return
        end
        self:StartCollectFile()
    elseif self._step == _ESteps_CollectPatch or self._step == _ESteps_CollectRepair then
        if not self._stepResult then
            self:OnCollectError()
            return
        end
        self:StartVerifyFile()
    elseif self._step == _ESteps_Verify then
        --验证文件总是成功的
        self:StartDownloadFile()
    elseif self._step == _ESteps_Download then
        if not self._stepResult then
            self:OnDownloadError()
            return
        end
        self:StartDownloadComplete()
    elseif self._step == _ESteps_DownloadComplete then
        self:RecordVersion()
        self:ClearPatchInfo()
        self:StartWaitUnloadBundle()
    elseif self._step == _ESteps_UnloadBundle then
        self:OnPatchFinished()
    end
end
---@endregion 更新流程

return LxPatchMgr
